      String[] args = new String[] {"arg1", "arg2"};
      CollectionsDeserializationBenchmark.main(args);
      mockedRunner.verify(() -> NonUploadingCaliperRunner.run(CollectionsDeserializationBenchmark.class, args));
    }
  }
}
